package Session;

sub new {
    my ($class, %opts) = @_;
    my $self = bless {
        session_dir    => $opts{session_dir}    || $SESSION_DIR,
        session_prefix => $opts{session_prefix} || $SESSION_PREFIX,
        cookie_name    => $opts{cookie_name}    || $SESSION_COOKIE,
        expire         => $opts{expire}         || $SESSION_EXPIRE,
        cgi            => $opts{cgi}            || CGI->new(),
        session_id     => undef,
        data           => {},
        is_new         => 0,
        modified       => 0,
    }, $class;

    $self->_init();
    return $self;
}

# Initialize session: load existing or create new
sub _init {
    my ($self) = @_;

    # Try to get session ID from cookie
    my %cookies = CGI::Cookie->fetch();
    if ($cookies{$self->{cookie_name}}) {
        my $sid = $cookies{$self->{cookie_name}}->value;
        # Validate session ID format (only hex characters allowed)
        if ($sid && $sid =~ /^[a-f0-9]{64}$/) {
            $self->{session_id} = $sid;
            if ($self->_load_session()) {
                # Check if session has expired
                if ($self->_is_expired()) {
                    $self->destroy();
                    $self->_create_new_session();
                }
                return;
            }
        }
    }

    # No valid session found, create a new one
    $self->_create_new_session();
}

# Generate a secure random session ID
sub _generate_session_id {
    my ($self) = @_;
    my $random_data = '';
    $random_data .= $$ . time() . rand(999999);

    # Add more entropy if /dev/urandom is available
    if (open my $fh, '<', '/dev/urandom') {
        my $bytes;
        read($fh, $bytes, 32);
        close $fh;
        $random_data .= $bytes;
    }

    return Digest::SHA::sha256_hex($random_data);
}

# Get the file path for a session
sub _session_file {
    my ($self, $sid) = @_;
    $sid ||= $self->{session_id};
    return File::Spec->catfile($self->{session_dir}, $self->{session_prefix} . $sid);
}

# Create a new session
sub _create_new_session {
    my ($self) = @_;
    $self->{session_id} = $self->_generate_session_id();
    $self->{data} = {
        _created  => time(),
        _accessed => time(),
        _expire   => $self->{expire},
    };
    $self->{is_new}    = 1;
    $self->{modified}  = 1;
    $self->_save_session();
}

# Load session data from file using Storable::retrieve
sub _load_session {
    my ($self) = @_;
    my $file = $self->_session_file();

    if (-f $file && -r $file) {
        eval {
            $self->{data} = lock_retrieve($file);
        };
        if ($@) {
            warn "Failed to retrieve session file '$file': $@";
            return 0;
        }

        # Update last accessed time
        $self->{data}{_accessed} = time();
        $self->{modified} = 1;
        return 1;
    }

    return 0;
}

# Save session data to file using Storable::nstore
sub _save_session {
    my ($self) = @_;
    return unless $self->{modified};

    my $file = $self->_session_file();

    eval {
        lock_nstore($self->{data}, $file);
        chmod 0600, $file;  # Restrict file permissions
    };
    if ($@) {
        warn "Failed to store session file '$file': $@";
        return 0;
    }

    $self->{modified} = 0;
    return 1;
}

# Check if session has expired
sub _is_expired {
    my ($self) = @_;
    my $accessed = $self->{data}{_accessed} || 0;
    my $expire   = $self->{data}{_expire}   || $self->{expire};
    return (time() - $accessed) > $expire;
}

# Get a session value
sub get {
    my ($self, $key) = @_;
    return $self->{data}{$key};
}

# Set a session value
sub set {
    my ($self, $key, $value) = @_;
    $self->{data}{$key} = $value;
    $self->{modified} = 1;
    return $value;
}

# Delete a session value
sub delete {
    my ($self, $key) = @_;
    my $old = delete $self->{data}{$key};
    $self->{modified} = 1;
    return $old;
}

# Check if a key exists in session
sub exists {
    my ($self, $key) = @_;
    return exists $self->{data}{$key};
}

# Get all user-defined keys (excluding internal keys starting with _)
sub keys {
    my ($self) = @_;
    return grep { !/^_/ } keys %{$self->{data}};
}

# Get the session ID
sub id {
    my ($self) = @_;
    return $self->{session_id};
}

# Check if this is a new session
sub is_new {
    my ($self) = @_;
    return $self->{is_new};
}

# Get the session cookie for sending to the client
sub cookie {
    my ($self) = @_;
    return CGI::Cookie->new(
        -name     => $self->{cookie_name},
        -value    => $self->{session_id},
        -expires  => '+' . $self->{expire} . 's',
        -path     => '/',
        -httponly  => 1,
        -secure   => ($ENV{HTTPS} ? 1 : 0),
        -samesite => 'Lax',
    );
}

# Destroy the current session
sub destroy {
    my ($self) = @_;
    my $file = $self->_session_file();

    if (-f $file) {
        unlink $file or warn "Failed to delete session file '$file': $!";
    }

    $self->{data}     = {};
    $self->{modified} = 0;
    $self->{session_id} = undef;
}

# Flush/save session data (call at end of request)
sub flush {
    my ($self) = @_;
    return $self->_save_session();
}

# Regenerate session ID (for security, e.g., after login)
sub regenerate_id {
    my ($self) = @_;
    my $old_file = $self->_session_file();

    # Generate new ID
    $self->{session_id} = $self->_generate_session_id();
    $self->{modified} = 1;

    # Remove old session file
    if (-f $old_file) {
        unlink $old_file or warn "Failed to delete old session file '$old_file': $!";
    }

    # Save with new ID
    $self->_save_session();
    return $self->{session_id};
}

# Class method: clean up expired sessions
sub cleanup_expired {
    my ($class, %opts) = @_;
    my $dir    = $opts{session_dir}    || $SESSION_DIR;
    my $prefix = $opts{session_prefix} || $SESSION_PREFIX;
    my $expire = $opts{expire}         || $SESSION_EXPIRE;
    my $count  = 0;

    opendir(my $dh, $dir) or do {
        warn "Cannot open session directory '$dir': $!";
        return 0;
    };

    while (my $entry = readdir($dh)) {
        next unless $entry =~ /^\Q$prefix\E[a-f0-9]{64}$/;
        my $file = File::Spec->catfile($dir, $entry);

        eval {
            my $data = retrieve($file);
            if ($data && ref $data eq 'HASH') {
                my $accessed = $data->{_accessed} || 0;
                my $sess_exp = $data->{_expire}   || $expire;
                if ((time() - $accessed) > $sess_exp) {
                    unlink $file;
                    $count++;
                }
            }
        };
        if ($@) {
            # Corrupted session file, remove it
            unlink $file;
            $count++;
        }
    }

    closedir($dh);
    return $count;
}

# Dump session data (for debugging)
sub dump {
    my ($self) = @_;
    require Data::Dumper;
    return Data::Dumper::Dumper($self->{data});
}

sub DESTROY {
    my ($self) = @_;
    $self->flush() if $self->{modified} && $self->{session_id};
}

